```python
# src/board.py

class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def make_king(self):
        self.king = True


class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        colors = ["white", "black"]
        for row, color in enumerate(colors):
            for col in range((1 + (row % 2)) % 2, 8, 2):
                if row < 3:
                    self.board[row][col] = Piece(color)
                elif row > 4:
                    self.board[row][col] = Piece(color)

    def display(self):
        for row in range(8):
            print(" ".join(f"{piece.color[0]}{'K' if piece.king else ''}" if piece else " " for piece in self.board[row]))

    def move_piece(self, from_row, from_col, to_row, to_col):
        piece = self.board[from_row][from_col]
        if piece:
            self.board[to_row][to_col] = piece
            self.board[from_row][from_col] = None

    def is_valid_move(self, from_row, from_col, to_row, to_col):
        piece = self.board[from_row][from_col]
        if not piece:
            return False

        # Check for standard move
        if abs(from_row - to_row) == 1 and abs(from_col - to_col) == 1:
            return True

        # Check for capture
        if abs(from_row - to_row) == 2 and abs(from_col - to_col) == 2:
            intermediate_piece = self.board[(from_row + to_row) // 2][(from_col + to_col) // 2]
            return intermediate_piece and intermediate_piece.color != piece.color

        return False
```

