# src/game_flow.py

from .board import Board

def get_move_input(player):
    while True:
        move = input(f"Player {player}, enter your move (e.g., a1-b2): ").strip().lower()
        if len(move) == 4 and move[0] in 'abcdefgh' and move[1] in '12345678' and move[2] in 'abcdefgh' and move[3] in '12345678':
            return int(move[1]) - 1, ord(move[0]) - 97, int(move[3]) - 1, ord(move[2]) - 97
        print("Invalid move. Please try again.")

def main():
    board = Board()
    current_player = 'white'

    while True:
        board.display()
        from_row, from_col, to_row, to_col = get_move_input(current_player)

        if not board.is_valid_move(from_row, from_col, to_row, to_col):
            print("Invalid move. Please try again.")
            continue

        board.move_piece(from_row, from_col, to_row, to_col)

        # Check for win or draw state
        # For simplicity, we'll just check if the opponent has any pieces left
        if not any(piece is not None and piece.color != current_player for row in board.board for piece in row):
            print(f"Player {current_player.capitalize()} wins!")
            break

        current_player = 'black' if current_player == 'white' else 'white'

if __name__ == "__main__":
    main()
```

